from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a monument (or related entity) into a single
    fluent sentence. All triples are combined; each predicate is expressed with a
    suitable phrase.
    """
    if not triples:
        return ""

    # Helper to format dates naturally
    def format_date(date_str: str) -> str:
        date_str = date_str.strip('"')
        if len(date_str) == 10 and date_str[4] == '-' and date_str[7] == '-':
            try:
                year, month, day = date_str.split('-')
                months = ["January", "February", "March", "April", "May", "June",
                         "July", "August", "September", "October", "November", "December"]
                return f"{months[int(month)-1]} {day}, {year}"
            except:
                return date_str
        return date_str

    # Build a mapping of subjects to their triples
    subject_triples = {}
    for triple in triples:
        if triple.subject not in subject_triples:
            subject_triples[triple.subject] = []
        subject_triples[triple.subject].append(triple)

    # Identify the main subject (likely the monument itself)
    # Heuristic: pick subject that appears first or has most triples
    main_subject = triples[0].subject
    main_triples = subject_triples.get(main_subject, [])

    # Collect all information from main subject triples
    info = {}
    for triple in main_triples:
        p = triple.predicate
        o = triple.object.strip('"')
        info[p] = o

    # Collect related entity info (from other subjects that are referenced)
    related_entities = {}
    for subject, subject_trips in subject_triples.items():
        if subject != main_subject:
            related_entities[subject] = {}
            for triple in subject_trips:
                related_entities[subject][triple.predicate] = triple.object.strip('"')

    # Build the sentence parts
    sentence_parts = []

    # Start with main subject and category
    if "category" in info:
        sentence_parts.append(f"{main_subject} is a {info['category']}")
    else:
        sentence_parts.append(f"{main_subject}")

    # Add monument-specific attributes
    additional_clauses = []
    if "district" in info:
        additional_clauses.append(f"is part of {info['district']}")
    if "established" in info:
        additional_clauses.append(f"was established on {format_date(info['established'])}")
    if "foundingDate" in info:
        additional_clauses.append(f"was founded on {format_date(info['foundingDate'])}")
    if "inaugurationDate" in info:
        additional_clauses.append(f"was inaugurated on {format_date(info['inaugurationDate'])}")
    if "owner" in info:
        additional_clauses.append(f"is owned by {info['owner']}")
    if "owningOrganisation" in info:
        additional_clauses.append(f"is owned by {info['owningOrganisation']}")
    if "dedicatedTo" in info:
        additional_clauses.append(f"is dedicated to {info['dedicatedTo']}")
    if "designer" in info:
        additional_clauses.append(f"was designed by {info['designer']}")
    if "material" in info:
        additional_clauses.append(f"is made of {info['material']}")
    if "nativeName" in info:
        additional_clauses.append(f'with native name "{info["nativeName"]}"')

    if additional_clauses:
        sentence_parts[-1] += ", " + ", ".join(additional_clauses)

    # Build location chain
    location_parts = []
    if "municipality" in info:
        location_parts.append(info["municipality"])
    if "state" in info:
        location_parts.append(info["state"])
    if "location" in info:
        location_parts.append(info["location"])
    if "country" in info:
        location_parts.append(info["country"])

    if location_parts:
        location_str = ", ".join(location_parts)
        if len(location_parts) == 1:
            sentence_parts[-1] += f", located in {location_str}"
        else:
            sentence_parts[-1] += f", located in {location_str}"

    # Add related entity information
    for entity_name, entity_info in related_entities.items():
        if "nearestCity" in entity_info:
            sentence_parts[-1] += f", near {entity_info['nearestCity']}"
        if "capital" in entity_info:
            sentence_parts[-1] += f", where the capital is {entity_info['capital']}"
        if "language" in entity_info:
            sentence_parts[-1] += f", where the language is {entity_info['language']}"
        if "ethnicGroup" in entity_info:
            sentence_parts[-1] += f", with ethnic group {entity_info['ethnicGroup']}"
        if "currency" in entity_info:
            sentence_parts[-1] += f", which uses {entity_info['currency']}"
        if "largestCity" in entity_info:
            sentence_parts[-1] += f", whose largest city is {entity_info['largestCity']}"
        if "leader" in entity_info:
            sentence_parts[-1] += f", led by {entity_info['leader']}"
        if "hasToItsNorth" in entity_info:
            sentence_parts[-1] += f", with {entity_info['hasToItsNorth']} to its north"
        if "hasToItsSouthwest" in entity_info:
            sentence_parts[-1] += f", with {entity_info['hasToItsSouthwest']} to its southwest"
        if "hasToItsWest" in entity_info:
            sentence_parts[-1] += f", with {entity_info['hasToItsWest']} to its west"

    # Join all parts into final sentence
    return ". ".join(sentence_parts) + "."

# EVOLVE-BLOCK-END
